package com.izonehub.stores.inventory;import com.izonehub.stores.item.Item;import com.izonehub.stores.store.Store;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;
@Service public class InventoryCommandService{private final InventoryRepository repo; public InventoryCommandService(InventoryRepository repo){this.repo=repo;} @Transactional public StoreInventory receive(Store store,Item item,BigDecimal qty){StoreInventory inv=findOrCreate(store,item);inv.receiveUsable(qty);return repo.save(inv);} @Transactional public StoreInventory dispatch(Store store,Item item,BigDecimal qty){StoreInventory inv=findOrCreate(store,item);inv.dispatch(qty);return repo.save(inv);} private StoreInventory findOrCreate(Store store,Item item){return repo.findByStoreAndItem(store,item).orElseGet(()->new StoreInventory(store,item));}}
